import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def urgency_penalty(arrive_time, window):
        if arrive_time > window[1]:
            return np.inf
        elif arrive_time < window[0]:
            return window[0] - arrive_time
        return 0

    urgencies = [urgency_penalty(current_time + travel_time(cur_truck_pos, cust), tw) for cust, tw in zip(unvisited_customers, time_windows)]
    costs = [travel_time(cur_truck_pos, cust) for cust in unvisited_customers]

    # Enhanced Future-Centric estimation of spark coefficients
    spark_coefficients = []
    for i, cust in enumerate(unvisited_customers):
        future_impact = 0
        for j, o_truck_pos in enumerate(all_truck_pos):
            if not np.array_equal(o_truck_pos, cur_truck_pos):
                o_arrive_time = current_time + travel_time(o_truck_pos, cust)
                future_impact += urgency_penalty(o_arrive_time, time_windows[i])

        spark_coefficient = costs[i] + urgencies[i] * (1 + 0.5 * future_impact)  # Adjusting future urgency impact dynamically
        spark_coefficients.append(spark_coefficient)

    best_node = np.argmin(spark_coefficients)
    return best_node
